import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token'); 

  const handleLogout = () => {
    localStorage.removeItem('token');
    alert("Logged out successfully!");
    navigate('/login');
  };

  return (
    <nav style={styles.nav}>
      <div style={styles.logo}>
        <Link to="/" style={styles.logoLink}>GigNexus<span>.</span></Link>
      </div>

      <div style={styles.navLinks}>
        <Link to="/" style={styles.link}>Home</Link>
        <Link to="/marketplace" style={styles.link}>Marketplace</Link>
        <Link to="/scanner" style={styles.link}>Scanner</Link>
        <Link to="/contact" style={styles.link}>Contact</Link>

        {token ? (
          <>
            <Link to="/dashboard" style={styles.link}>Dashboard</Link>
            <button onClick={handleLogout} style={styles.logoutBtn}>Logout</button>
          </>
        ) : (
          <Link to="/login" style={styles.joinBtn}>Join Us</Link>
        )}
      </div>
    </nav>
  );
};

const styles = {
  nav: { display: 'flex', justifyContent: 'space-between', padding: '20px 50px', background: '#000', color: '#fff', alignItems: 'center' },
  logoLink: { fontSize: '28px', fontWeight: 'bold', color: '#00d2ff', textDecoration: 'none' },
  navLinks: { display: 'flex', gap: '25px', alignItems: 'center' },
  link: { textDecoration: 'none', color: '#ccc', fontSize: '16px', fontWeight: '500' },
  joinBtn: { background: '#00d2ff', color: '#000', padding: '10px 20px', borderRadius: '5px', textDecoration: 'none', fontWeight: 'bold' },
  logoutBtn: { background: '#ff4d4d', color: '#fff', border: 'none', padding: '10px 20px', borderRadius: '5px', cursor: 'pointer' }
};

export default Navbar;
